// Helmet Icon PNG as Base64
const HELMET_ICON_BASE64 = 'data:image/png;base64,';

// Motocross Helmet Outline Icon - Pure white outline, no fill
const HelmetOutlineIcon = ({ active = true }) => (
  <svg
    viewBox="0 0 24 24"
    className={`w-5 h-5 ${active ? 'opacity-100' : 'opacity-30'}`}
    fill="none"
    stroke="currentColor"
    strokeWidth="1.8"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    {/* Helmet dome/shell */}
    <path d="M4 14 C4 8, 8 3, 14 3 C18 3, 21 6, 21 10 L21 13" />
    {/* Visor peak at top */}
    <path d="M6 10 C8 8, 12 7, 16 7 L21 5" />
    {/* Face shield/goggle area */}
    <path d="M4 14 C4 15, 5 16.5, 8 16.5 C10 16.5, 11 15, 12 14" />
    {/* Chin guard - left side down */}
    <path d="M4 14 L4 18 C4 20, 6 21, 9 21" />
    {/* Chin guard - bottom curve */}
    <path d="M9 21 C13 21, 17 20, 19 18 L19 14" />
    {/* Back of helmet */}
    <path d="M21 13 C21 15, 20 17, 19 18" />
    {/* Mouth vent detail */}
    <path d="M6 19 L8 19" />
  </svg>
);

const DifficultyIcon = ({ level }) => {
  if (!level) return null;
  return (
    <div className="flex items-center gap-0.5 text-stone-300">
      {[1, 2, 3].map((i) => (
        <HelmetOutlineIcon key={i} active={i <= level} />
      ))}
    </div>
  );
};

// ============================================================================
// EVENTS VIEW CONTEXT - For preserving state across navigation
// ============================================================================

const EventsViewContext = createContext(null);

function useEventsView() {
  const context = useContext(EventsViewContext);
  if (!context) {
    // Return a default implementation if not wrapped (for backwards compatibility)
    return {
      savedState: null,
      saveState: () => { },
      clearState: () => { },
      hasSavedState: () => false,
    };
  }
  return context;
}

function EventsViewProvider({ children }) {
  const [savedState, setSavedState] = useState(null);

  const saveState = useCallback((state) => {
    setSavedState({
      ...state,
      timestamp: Date.now(),
    });
  }, []);

  const clearState = useCallback(() => {
    setSavedState(null);
  }, []);

  const hasSavedState = useCallback(() => {
    return savedState !== null;
  }, [savedState]);

  return (
    <EventsViewContext.Provider value={{ savedState, saveState, clearState, hasSavedState }}>
      {children}
    </EventsViewContext.Provider>
  );
}

