// Maps dropdown values to mainDiscipline + subDiscipline for proper initialization

const DISCIPLINE_OPTIONS = [
  { value: 'none', labelKey: 'noPreference', main: 'trail-adventures', sub: 'all' },
  { value: 'trail', labelKey: 'trailRiding', main: 'trail-adventures', sub: 'trail' },
  { value: 'enduro', labelKey: 'enduro', main: 'trail-adventures', sub: 'enduro' },
  { value: 'hard-enduro', labelKey: 'hardEnduro', main: 'trail-adventures', sub: 'hard-enduro' },
  { value: 'mx', labelKey: 'mx', main: 'trail-adventures', sub: 'mx' },
  { value: 'rallyes', labelKey: 'rallyes', main: 'rallyes', sub: 'all' },
  { value: 'adventure-trips', labelKey: 'adventureTrips', main: 'adventure-trips', sub: 'all' },
  { value: 'skills-camps', labelKey: 'skillsCamps', main: 'skills-camps', sub: 'all' },
  { value: 'offroad-festivals', labelKey: 'offroadFestivals', main: 'offroad-festivals', sub: 'all' },
];

function getDisciplineConfig(value) {
  return DISCIPLINE_OPTIONS.find(opt => opt.value === value) || DISCIPLINE_OPTIONS[0];
}

