// Helper Functions
function formatDate(dateStr, locale = 'de-DE') {
  const date = new Date(dateStr);
  return date.toLocaleDateString(locale, { day: '2-digit', month: '2-digit' });
}

// New function for date range display: DD.MM – DD.MM.YY
function formatDateRange(startDateStr, endDateStr) {
  const startDate = new Date(startDateStr);
  const endDate = new Date(endDateStr);

  const startDay = String(startDate.getDate()).padStart(2, '0');
  const startMonth = String(startDate.getMonth() + 1).padStart(2, '0');
  const startYear = String(startDate.getFullYear()).slice(-2);

  const endDay = String(endDate.getDate()).padStart(2, '0');
  const endMonth = String(endDate.getMonth() + 1).padStart(2, '0');
  const endYear = String(endDate.getFullYear()).slice(-2);

  // Check if spans year boundary
  if (startDate.getFullYear() !== endDate.getFullYear()) {
    return `${startDay}.${startMonth}.${startYear} – ${endDay}.${endMonth}.${endYear}`;
  }

  return `${startDay}.${startMonth} – ${endDay}.${endMonth}.${endYear}`;
}

// ============================================================================
// DATE UTILITIES FOR PAST EVENT AGE CALCULATION
// ============================================================================

function getEventAgeInYears(eventEndDate) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const endDate = new Date(eventEndDate);
  endDate.setHours(0, 0, 0, 0);

  const diffTime = today - endDate;
  const diffYears = diffTime / (1000 * 60 * 60 * 24 * 365.25);
  return diffYears;
}

// Returns: 'recent' (<1 year), 'archived' (1-3 years), 'expired' (>3 years), 'future' (not past)
function getPastEventStatus(eventEndDate) {
  // Permanent events (e.g. MX-Tracks) have no endDate — always treat as active
  if (!eventEndDate) return 'future';

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const endDate = new Date(eventEndDate);
  endDate.setHours(0, 0, 0, 0);

  if (endDate > today) return 'future';

  const ageInYears = getEventAgeInYears(eventEndDate);

  if (ageInYears < 1) return 'recent'; // Clickable
  if (ageInYears < 3) return 'archived'; // Visible but not clickable
  return 'expired'; // Should be hidden/deleted
}

function calculateDuration(start, end, t = null) {
  const startDate = new Date(start);
  const endDate = new Date(end);
  const days = Math.ceil((endDate - startDate) / (1000 * 60 * 60 * 24)) + 1;
  if (t) {
    return days === 1 ? t('day1') : `${days} ${t('days')}`;
  }
  return days === 1 ? '1 Tag' : `${days} Tage`;
}

function calculateDistance(lat1, lng1, lat2, lng2) {
  const R = 6371; // Earth's radius in km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

