function translateLocation(location, language) {
  if (!location) return location;
  const parts = location.split(',').map(p => p.trim());
  const translatedParts = parts.map(part => {
    const translation = countryTranslations[part];
    return translation ? translation[language] || part : part;
  });
  return translatedParts.join(', ');
}

function isThisWeekend(dateStr) {
  const eventDate = new Date(dateStr);
  const today = new Date();
  const dayOfWeek = today.getDay();
  const daysUntilSaturday = (6 - dayOfWeek + 7) % 7;
  const saturday = new Date(today);
  saturday.setDate(today.getDate() + daysUntilSaturday);
  saturday.setHours(0, 0, 0, 0);
  const sunday = new Date(saturday);
  sunday.setDate(saturday.getDate() + 1);
  sunday.setHours(23, 59, 59, 999);
  return eventDate >= saturday && eventDate <= sunday;
}

// Discipline Badge Config - Trail Adventures only
const DISCIPLINE_BADGE_CONFIG = {
  'trail': { label: 'Trail', bg: 'bg-emerald-600', text: 'text-white' },
  'enduro': { label: 'Enduro', bg: 'bg-amber-500', text: 'text-stone-900' },
  'hard-enduro': { label: 'Hard Enduro', bg: 'bg-red-600', text: 'text-white' },
};

function DisciplineBadge({ event, size = 'md' }) {
  if (event.category !== 'trail-adventures') return null;
  const config = DISCIPLINE_BADGE_CONFIG[event.subcategory];
  if (!config) return null;
  const sizeClass = size === 'sm' ? 'px-1.5 py-0.5 text-[10px]' : size === 'lg' ? 'px-3 py-1.5 text-xs' : 'px-2 py-1 text-xs';
  return <span className={`${sizeClass} ${config.bg} ${config.text} font-bold rounded-md shadow-lg`}>{config.label}</span>;
}

